glsl4.vert:
precision highp float;
layout(set = 0, binding = 0) uniform CCGlobal {
  highp   vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_nativeSize;
};
layout(set = 0, binding = 1) uniform CCCamera {
  highp   mat4 cc_matView;
  highp   mat4 cc_matViewInv;
  highp   mat4 cc_matProj;
  highp   mat4 cc_matProjInv;
  highp   mat4 cc_matViewProj;
  highp   mat4 cc_matViewProjInv;
  highp   vec4 cc_cameraPos;
  mediump vec4 cc_screenScale;
  mediump vec4 cc_exposure;
  mediump vec4 cc_mainLitDir;
  mediump vec4 cc_mainLitColor;
  mediump vec4 cc_ambientSky;
  mediump vec4 cc_ambientGround;
  mediump vec4 cc_fogColor;
  mediump vec4 cc_fogBase;
  mediump vec4 cc_fogAdd;
  mediump vec4 cc_nearFar;
  mediump vec4 cc_viewPort;
};
layout(location = 0) in vec3 a_position;
layout(location = 1) in vec2 a_texCoord;
layout(location = 2) in vec4 a_color;
layout(location = 0) out vec2 uv0;
layout(location = 1) out vec4 v_color;
vec4 vert () {
  vec4 pos = vec4(a_position, 1.0);
  pos = cc_matViewProj * pos;
  uv0 = a_texCoord;
  v_color = a_color;
  return pos;
}
void main() { gl_Position = vert(); }

glsl4.frag:
precision highp float;
layout(set = 0, binding = 0) uniform CCGlobal {
  highp   vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_nativeSize;
};
layout(set = 0, binding = 1) uniform CCCamera {
  highp   mat4 cc_matView;
  highp   mat4 cc_matViewInv;
  highp   mat4 cc_matProj;
  highp   mat4 cc_matProjInv;
  highp   mat4 cc_matViewProj;
  highp   mat4 cc_matViewProjInv;
  highp   vec4 cc_cameraPos;
  mediump vec4 cc_screenScale;
  mediump vec4 cc_exposure;
  mediump vec4 cc_mainLitDir;
  mediump vec4 cc_mainLitColor;
  mediump vec4 cc_ambientSky;
  mediump vec4 cc_ambientGround;
  mediump vec4 cc_fogColor;
  mediump vec4 cc_fogBase;
  mediump vec4 cc_fogAdd;
  mediump vec4 cc_nearFar;
  mediump vec4 cc_viewPort;
};
layout(location = 0) in vec2 uv0;
layout(location = 1) in vec4 v_color;
layout(set = 1, binding = 0) uniform Constant {
  vec4 burstColor;
  vec4 animParams;
  vec4 extraParams;
};
vec4 frag () {
  float progress  = animParams.x;
  float speed     = animParams.y;
  float radius    = animParams.z;
  float thickness = animParams.w;
  float distLevel = extraParams.x;
  float glowLevel = extraParams.y;
  float squash    = extraParams.z;
  float spread    = extraParams.w;
  if (progress <= 0.011 || progress >= 0.95) {
    return vec4(0.0);
  }
  float t = cc_time.x * speed;
  vec2 uv = uv0 - vec2(0.5);
  uv.y *= squash;
  float angle = atan(uv.y, uv.x);
  vec2 originalUV = uv0;
  float cosA = abs(cos(angle));
  float taperStart = spread * 0.95;
  float taperEnd   = min(taperStart + 0.3, 0.99);
  float maskStart  = spread * 0.80;
  float maskEnd    = min(maskStart + 0.2, 0.99);
  float taper   = smoothstep(taperStart, taperEnd, cosA);
  float arcMask = smoothstep(maskStart, maskEnd, cosA);
  float distort = (sin(angle * 20.0 - t * 5.0) * 0.015
                + sin(angle * 45.0 + t * 8.0) * 0.010
                + cos(angle * 85.0 - t * 12.0) * 0.005) * distLevel;
  distort *= (0.2 + 0.8 * taper);
  float d = length(uv) + distort;
  float distToLine = abs(d - radius);
  float currentThickness = thickness * (0.05 + 0.95 * taper);
  float core = smoothstep(currentThickness * 0.15, 0.0, distToLine);
  float glow = smoothstep(currentThickness, 0.0, distToLine) * 0.5;
  float fadeIn  = smoothstep(0.011, 0.15, progress);
  float fadeOut = smoothstep(0.95, 0.5, progress);
  float envelope = fadeIn * fadeOut;
  vec3 glowColor = burstColor.rgb * glow * 3.0 * glowLevel;
  vec3 coreColor = vec3(1.0) * core * 1.5;
  vec3 finalRGB = (glowColor + coreColor) * arcMask * envelope;
  float finalAlpha = clamp((glow + core) * arcMask * envelope * 3.0, 0.0, 1.0);
  return vec4(finalRGB, finalAlpha) * v_color;
}
layout(location = 0) out vec4 cc_FragColor;
void main() { cc_FragColor = frag(); }

